mapper.select:
SELECT FROM unit_master u INNER JOIN property p ON p.id = u.property_id INNER JOIN tower t ON t.id = u.tower_id WHERE u.is_deleted = FALSE
AND (LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(u.unit_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(u.occupancy_status) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(t.tower_code) LIKE CONCAT('%', LOWER(#{search}), '%'))
ORDER BY u.id DESC LIMIT #{limit} OFFSET #{offset}
